    private fun assetShape(assetName: String, pathData: String): BlobShapeTemplate {
        val index = assetName.substringAfter('_').toIntOrNull() ?: 0
        val nodes = parseBlobmakerPath(pathData)
        return BlobShapeTemplate(
            preset = BlobShapePreset.entries[index % BlobShapePreset.entries.size],
            points = nodes.toShapePointMultipliers(),
            curveTension = DEFAULT_BLOB_CURVE_TENSION,
            nodes = nodes,
            assetName = assetName,
        )
    }

    private fun parseBlobmakerPath(pathData: String): List<BlobShapeNode> {
        val tokens = pathToken.findAll(pathData).map { it.value }.toList()
        val nodes = mutableListOf<BlobShapeNode>()
        var index = 0
        var command = ""

        fun hasNumber(): Boolean = index < tokens.size && !tokens[index].isCommand()
        fun nextNumber(): Float = tokens[index++].toFloat()
        fun nextPoint(): MapPoint = MapPoint(nextNumber() / SOURCE_VIEWBOX_RADIUS, nextNumber() / SOURCE_VIEWBOX_RADIUS)

        while (index < tokens.size) {
            if (tokens[index].isCommand()) {
                command = tokens[index++]
            }

            when (command) {
                "M" -> {
                    if (hasNumber()) {
                        val point = nextPoint()
                        nodes += BlobShapeNode(anchor = point, inHandle = point, outHandle = point)
                    }
                }

                "C" -> {
                    while (hasNumber()) {
                        val controlOne = nextPoint()
                        val controlTwo = nextPoint()
                        val end = nextPoint()
                        if (nodes.isEmpty()) return emptyList()

                        val current = nodes.lastIndex
                        nodes[current] = nodes[current].copy(outHandle = controlOne)
                        val first = nodes.first()
                        if (end.nearlyEquals(first.anchor)) {
                            nodes[0] = first.copy(inHandle = controlTwo)
                        } else {
                            nodes += BlobShapeNode(anchor = end, inHandle = controlTwo, outHandle = end)
                        }
                    }
                }

                "Z", "z" -> Unit
                else -> return emptyList()
            }
        }

        return nodes.takeIf { it.isValidBlobShapeNodes() } ?: List(8) { 1f }.toBlobShapeNodes()
    }

    private fun MapPoint.nearlyEquals(other: MapPoint): Boolean {
        return hypot(x - other.x, y - other.y) < 0.001f
    }

    private fun String.isCommand(): Boolean {
        return length == 1 && first().isLetter()
    }

    private const val SOURCE_VIEWBOX_RADIUS = 100f
}
